import { Link } from "wouter";
import { ArrowRight, Atom, Calculator, FlaskConical, Ruler, Zap } from "lucide-react";
import { calculatorRoutes } from "@/data/siteRoutes";

type RelatedItem = string | { label: string; href: string };

const FALLBACK_HREFS: Record<string, string> = {
  "Period Calculator": "/frequency-calculator",
  "Sound Wavelength Calculator": "/wavelength-calculator",
  "Fluid Mechanics Calculator": "/pressure-calculator",
  "Temperature Calculator": "/conversion-calculator",
  "Charles's Law Calculator": "/charles-law-calculator",
};

const CATEGORY_STYLES = {
  Science: { Icon: Atom, color: "text-cyan-600 bg-cyan-50 dark:text-cyan-300 dark:bg-cyan-950/50" },
  Chemistry: { Icon: FlaskConical, color: "text-emerald-600 bg-emerald-50 dark:text-emerald-300 dark:bg-emerald-950/50" },
  Measurement: { Icon: Ruler, color: "text-sky-600 bg-sky-50 dark:text-sky-300 dark:bg-sky-950/50" },
  Tools: { Icon: Calculator, color: "text-slate-600 bg-slate-100 dark:text-slate-300 dark:bg-slate-800/60" },
} as const;

function slugFromLabel(label: string) {
  return label
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/'/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
}

function resolveRelatedItem(item: RelatedItem, fallbackCategory: "Science" | "Chemistry") {
  if (typeof item !== "string") return item;

  const directHref = `/${slugFromLabel(item)}`;
  const calculatedHref = directHref.endsWith("-calculator") ? directHref : `${directHref}-calculator`;
  const route = calculatorRoutes.find((entry) => entry.path === calculatedHref);

  return {
    label: item,
    href: route?.path ?? FALLBACK_HREFS[item] ?? `/?cat=${fallbackCategory}`,
  };
}

function categoryForHref(href: string, fallbackCategory: "Science" | "Chemistry") {
  return calculatorRoutes.find((entry) => entry.path === href)?.category ?? fallbackCategory;
}

export default function ScienceRelatedCalculatorCards({
  title,
  items,
  fallbackCategory,
}: {
  title: string;
  items: RelatedItem[];
  fallbackCategory: "Science" | "Chemistry";
}) {
  const relatedItems = items.map((item) => resolveRelatedItem(item, fallbackCategory)).slice(0, 4);

  return (
    <section className="mt-10" aria-labelledby="science-related-calculators-heading">
      <h2 id="science-related-calculators-heading" className="text-lg font-bold text-foreground mb-4 flex items-center gap-2">
        <Calculator className="w-4 h-4 text-primary flex-shrink-0" />
        {title}
      </h2>
      <div className="grid grid-cols-2 gap-2.5 sm:grid-cols-4">
        {relatedItems.map((item) => {
          const category = categoryForHref(item.href, fallbackCategory);
          const style =
            CATEGORY_STYLES[category as keyof typeof CATEGORY_STYLES] ??
            CATEGORY_STYLES[fallbackCategory] ??
            CATEGORY_STYLES.Tools;
          const Icon = style.Icon ?? Zap;

          return (
            <Link
              key={`${item.href}-${item.label}`}
              href={item.href}
              className="group relative flex min-w-0 flex-col rounded-xl border border-border bg-card p-3 transition-all duration-150 hover:border-primary/40 hover:shadow-md active:scale-[0.98]"
            >
              <div className="mb-2 flex items-center justify-between gap-2">
                <div className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-lg ${style.color}`}>
                  <Icon className="h-4 w-4" />
                </div>
                <ArrowRight className="h-4 w-4 flex-shrink-0 text-muted-foreground transition-all group-hover:translate-x-0.5 group-hover:text-primary" />
              </div>
              <span className="mb-1 truncate text-[9px] font-bold uppercase tracking-wide text-muted-foreground">{category}</span>
              <h3 className="line-clamp-2 text-xs font-bold leading-snug text-foreground transition-colors group-hover:text-primary">
                {item.label}
              </h3>
            </Link>
          );
        })}
      </div>
    </section>
  );
}
